export default {
  components: {
    crmtimeline,
    crmnote,
    crmattachment,
    crmsendemail,
    crmproduct,
    crmcall,
    modalattachment,
    modaltask,
    modalevent,
    modalcall,
    modelquoteemail,
    modalproduct,
    modaldeploy,
    crmreadmore,
    purchaseorderpreview,
    ManageInward
  },
  data() {
    return {
      activeKey: 1,
      isNotes: false,
      isAttachment: false,
      isTask: false,
      isFollowup: false,
      isScheduleCall: false,
      isSendEmail: false,
      iscontactDetails: null,
      showContactModal: false,
      showProductModal: false,
      showAddTaskModal: false,
      showAddEventModal: false,
      showCallModal: false,
      sendEmailModal: false,
      showAttachmentModal: false,
      LeftViewData: [],
      noteData: [],
      RightViewData: null,
      attachmentData: [],
      ginData: [],
      activitiesData: null,
      timelinedata: [],
      productData: null,
      productHeaders: null,
      contactsData: null,
      contactsHeader: null,
      noRecordForTab: false,
      isShowNoteDialogue: false,
      leadsHeader: null,
      dealsHeader: null,
      dealsData: null,
      leadsData: null,
      EmailData: [],
      EmailLogData: [],
      template1: false,
      template2: false,
      template3: false,
      template4: false,
      CRMPurchaseOrder: false,
      SummaryData: [],
      TemplateName: null,
      orderNumber: "",
      createdAt: "",
      companyName: "",
      clientName: "",
      billingContactPerson: "",
      shippingContactPerson: "",
      billingFullAddress: "",
      billingAccountAddress: "",
      shippingFullAddress: "",
      shippingAccountAddress: "",
      billingCountryData: "",
      shippingCountryData: "",
      billingCityData: "",
      shippingCityData: "",
      billingStateData: "",
      shippingStateData: "",
      billingCountyData: "",
      shippingCountyData: "",
      billingZipCodeData: "",
      shippingZipCodeData: "",
      billingEmailData: "",
      shippingEmailData: "",
      billingUserPhoneData: "",
      shippingUserPhoneData: "",
      address: "",
      email: "",
      phoneNo: "",
      orderTitle: "",
      description: "",
      termAndCondition: "",
      subtotal: "",
      shippingCharges: "",
      adjustments: "",
      netTotal: "",
      callData: null,
      modalItem: null,
      quotationNumber: "--",
      noteText: "",
      SortBy: "",
      SortExp: "",
      PageNumber: 1,
      PageSize: 50,
      modalTaskItem: null,
      modalFollowUpItem: null,
      modalCallItem: null,
      modalDeleteItem: null,
      isView: false,
      modal: null,
      showAddEmailTemplate: false,
      showDeployModal: false,
      LocationSelect: null,
      stausName: "",
      ginid: null,
      NoteListType: "list",
      gin_lineItem_id: null,
      currentTab: "",
      userid: null,
      companyId: null,
      companylogo: null,
      containername: null,
      ApiURL: `id=${this.$route.params.id}&companyId=${this.companyId}}&userId=${this.userid}&moduleName=${this.$route.params.moduleName}&subModuleCode=${this.$route.params.subModuleCode}`,
      ApiURL1: `id=${this.$route.params.id}&moduleName=${this.$route.params.moduleName}&subModuleCode=${this.$route.params.subModuleCode}`,
      maxsize:
        "@TALYGEN.Models.ConfigurationRepository.GetConfigurationValueByKey(companyId, userid, 'CRM', 'CRMPerFileSize')",
      disallowedfiletypes:
        "@TALYGEN.Models.ConfigurationRepository.GetConfigurationValueByKey(companyId, userid,'CRM', 'CRMDisallowedFileTypes')",
      ApiURLEmail: `id=0&refId=${this.$route.params.id}&subModuleCode=${this.$route.params.subModuleCode}`,
      editUrl: `/CRM/ManagePurchaseOrder/${this.$route.params.id}/${this.$route.params.moduleName}/${this.$route.params.subModuleCode}`,
      isShowNotePopup: false,
      EmailListingApiURL: `id=0&refId=${this.$route.params.id}&subModuleCode=${this.$route.params.subModuleCode}`,
      PreviewData: null,
      isLoading: false,
      EmailResultBody: '',
      isAddGoodInwards: false,
      IsGINList: true,
      vendorName: ''
    };
  },
  created: function () {
    this.userid = this.GetUserInfo.ID;
    this.companyId = this.GetUserInfo.CompanyId;
    this.containername = this.GetUserInfo.ContainerName;
    this.companylogo = this.GetUserInfo.CompanyLogo;
    this.FetchData();
  },
  updated() {
    var vm = this;
    setTimeout(function () { vm.setHeaderForSelectedTab() }, 500);
  },
  methods: {
    DisableButton: function () {
      var vm = this;
      vm.isNotes = false;
      vm.isAttachment = false;
      vm.isTask = false;
      vm.isFollowup = false;
      vm.isScheduleCall = false;
      vm.isSendEmail = false;
      vm.isAddGoodInwards = false;
    },
    // OpenGoodInwards: function (){
    //   this.isAddGoodInwards = true
    //   this.IsGINList = false

    // } ,  
    OpenGoodInwards: function () {

      const vm = this;
      vm.isLoading = true;

      const param = `orderid=${vm.$route.params.id}`;

      LeadDataService.CheckAddGIN(param).then(function (response) {
        debugger
        var result = response.data.result;
        if (result == "Product_expire") {
          vm.ShowAlert(vm.$t("purchaseorderexpire"), "danger", true, vm.$t("Alert"));

        }
        else if (result == "AcceptandReject") {
          vm.ShowAlert(vm.$t("ginapproveandreject"), "danger", true, vm.$t("Alert"));
        }
        else if (result == "Recieved") {
          vm.ShowAlert(vm.$t("AllproductRecieved"), "danger", true, vm.$t("Alert"));
        }
        else {
          vm.isAddGoodInwards = true;
          vm.IsGINList = false;
        }

        // vm.isAddGoodInwards = true;
        // vm.IsGINList = false;
        vm.isLoading = false;

        // Optional: use res if needed
        // vm.formData = res;
      });

      // Note: if an error happens, it will be unhandled unless caught globally
    },
    closeGoodInwards: function () {
      this.isAddGoodInwards = false
      this.IsGINList = true
      this.loadData('GIN', '');

    },
    openCRMAttachmentModal: function () {
      if (
        typeof this.checkForAdditionalPermission !== "undefined" &&
        !this.checkForAdditionalPermission("AddAttachment")
      ) {
        alertR(
          Globalize.localize("additionalOwnerAuthorityWarning"),
          true,
          Globalize.localize("Alert")
        );
      } else {
        this.showAttachmentModal =
          this.showAttachmentModal ? false : true;
      }
    },
    openlocation: function (value) {
      if (value.gin_id != null && value.gin_id !== "undefined") {
        this.ginid = value.gin_id;
      } else {
        this.gin_lineItem_id = value;
      }
      this.showDeployModal = this.showDeployModal ? false : true;


    },
    commonApprove: function (LocationSelect) {
      this.LocationSelect = LocationSelect;
      if (this.LocationSelect != null) {
        var vm = this;
        var val = "";
        if (typeof this.ginid !== "undefined" && this.ginid != null) {
          val = this.ginid;
        } else {
          val = this.gin_lineItem_id;
        }
        if (val.length > 0 || val != "") {
          vm.confirmR(vm.$t("AreYouSureToApproveSelectedRecords"), true, null,
            function (result) {
              var postJSON = {
                ids: val,
                moduleName: "CRM",
                subModuleCode: "CRM_PURCHASE_ORDERS",
                approvaltype: "CRM_APPROVE",
                locationid: vm.LocationSelect,
                viewmode: vm.ginid == null ? "YES" : "",
              };
              var objectPostString = JSON.stringify(postJSON);
              LeadDataService.changestausInwards(objectPostString).then(
                function (response) {
                  var box = "";
                  if (response.data[0].Status == "Success") {
                    vm.ShowAlert("GIN Inward Approved Successfully", "success", true, vm.$t("Alert"));
                    vm.loadData("GIN");
                  } else {
                    box = vm.ShowAlert(vm.$t("Error Occur while Approving Record"), "failure", true, vm.$t("Alert"));
                  }
                  setTimeout(function () {
                    box.modal("hide");
                  }, 2000);
                }
              );
            });
        } else {
          vm.ShowAlert(vm.$t('LeaveApprove'), 'success', true, vm.$t('Alert'));
        }
      } else {
        vm.ShowAlert(vm.$t('Please Select the location in order to approve'), 'success', true, vm.$t('Alert'));
      }
    },
    commonReject: function (value) {
      var vm = this;
      var val = "";
      if (value.gin_id != null && value.gin_id !== "undefined") {
        vm.ginid = value;
        val = value.gin_id;
      } else {
        vm.gin_lineItem_id = value;
        val = vm.gin_lineItem_id;
      }
      if (val.length > 0 || val != "") {
        vm.confirmR(vm.$t("AreYouSureToRejectSelectedRecords"), true, null, function (result) {

          var postJSON = {
            ids: val,
            moduleName: "CRM",
            subModuleCode: "CRM_PURCHASE_ORDERS",
            approvaltype: "CRM_REJECT",
            locationid: "",
            viewmode: vm.ginid == null ? "YES" : "",
          };
          var objectPostString = JSON.stringify(postJSON);
          LeadDataService.changestausInwards(objectPostString).then(function (
            response
          ) {
            var box = "";
            if (response.data[0].Status == "Success") {
              vm.ShowAlert("GIN Inward Reject Successfully", "success", true, vm.$t("Alert"));
              vm.loadData("GIN");
              $("#tab-GIN").trigger("click");
            } else {
              vm.ShowAlert("GIN Inward " + vm.$t("RejectError"), "failure", true, vm.$t("Alert"));
            }
            setTimeout(function () {
              box.modal("hide");
            }, 2000);
          });
        });

      } else {
        vm.ShowAlert(vm.$t("RemoveReject"));
      }
    },
    FetchData: function () {
      var vm = this;
      vm.isLoading = true;
      LeadDataService.FormLayoutView(this.ApiURL).then(function (response) {
        var fullLeftJsonfilter = response.data.LEFTDATA.filter(item => item.name !== 'contact_id');
        var fullLeftJSON = fullLeftJsonfilter;
        var stausName = $.grep(fullLeftJSON, function (element, index) {
          return element.name == "status_id";
        });
        if (stausName != null && stausName.length > 0) {
          vm.stausName = stausName[0];
        }
        fullLeftJSON = $.grep(fullLeftJSON, function (element, index) {
          return element.form_field_visibility == "YES";
        });
        if (
          response.data.RIGHTDATA != null &&
          response.data.RIGHTDATA.length > 0
        ) {
          var fullJSON = response.data.RIGHTDATA;
          var gruopBy = "";
          $.each(
            fullJSON,
            $.proxy(function (index, item) {
              gruopBy = vm.$options.filters.formatDate(item.Complete_datetime);
              var chkGroup = $.grep(
                this.timelinedata,
                function (element, index) {
                  return element.groupKey == gruopBy;
                }
              );
              if (chkGroup.length == 0) {
                var returnedData = $.grep(fullJSON, function (element, index) {
                  return (
                    vm.$options.filters.formatDate(element.Complete_datetime) == gruopBy
                  );
                });
                if (returnedData.length > 0) {
                  var objGroup = {
                    groupKey: gruopBy,
                    groupData: returnedData,
                  };
                  vm.timelinedata.push(objGroup);
                }
              }
            }, vm)
          );
          vm.isLoading = false;
          vm.noRecordForTab = false;
        } else {
          vm.noRecordForTab = true;
        }
        if (fullLeftJSON != null && fullLeftJSON.length > 0) {
          var groupId = fullLeftJSON[0].group_id;
          $.each(
            fullLeftJSON,
            $.proxy(function (index, item) {
              if (item.name == "order_number") {
                this.quotationNumber = item.value;
              }
              if (item.name == 'account_id') {
                this.vendorName = item.value
              }
              var chkGroup = $.grep(
                this.LeftViewData,
                function (element, index) {
                  return element.group_id == groupId;
                }
              );
              if (chkGroup.length == 0) {
                var returnedData = $.grep(
                  fullLeftJSON,
                  function (element, index) {
                    return element.group_id == groupId;
                  }
                );
                if (returnedData.length > 0) {
                  var objGroup = {
                    group_id: groupId,
                    group_name: returnedData[0].group_name,
                    group_display_name: returnedData[0].group_display_name ? returnedData[0].group_display_name : returnedData[0].group_name,
                    LeftViewData: returnedData,
                  };
                  vm.LeftViewData.push(objGroup);
                }
              }
              groupId = item.group_id;
            }, vm)
          );
        }
        vm.isLoading = false;
      });
    },


    changeDateForAddNoteUsrEnd: function (value) {
      try {
        var timeFormat = Globalize.culture().calendar.patterns.t;
        timeFormat = String(timeFormat).replace("t", "A").replace("t", "");
        var getDate = new Date(
          moment(String(value)).year(),
          moment(String(value)).month(),
          moment(String(value)).date(),
          moment(String(value)).hours(),
          moment(String(value)).minutes()
        );
        if (userTimeZone[0].indexOf("+") >= 0) {
          getDate = new Date(
            getDate.setHours(
              getDate.getHours() - parseInt(userTimeZone[0].replace("+", ""))
            )
          );
          getDate = new Date(
            getDate.setMinutes(getDate.getMinutes() - parseInt(userTimeZone[1]))
          );
        } else if (userTimeZone[0].indexOf("-") >= 0) {
          getDate = new Date(
            getDate.setHours(
              getDate.getHours() + parseInt(userTimeZone[0].replace("-", ""))
            )
          );
          getDate = new Date(
            getDate.setMinutes(getDate.getMinutes() + parseInt(userTimeZone[1]))
          );
        }
        return moment(getDate, "YYYY-MM-DD HH:mm").format(
          String(Globalize.culture().calendar.patterns.d).toUpperCase() +
          " " +
          String(timeFormat)
        );
      } catch (e) {
        var timeFormat = Globalize.culture().calendar.patterns.t;
        timeFormat = String(timeFormat).replace("t", "a").replace("t", "");
        return moment(String(value)).format(
          String(Globalize.culture().calendar.patterns.d).toUpperCase() +
          " " +
          String(timeFormat)
        );
      }
    },
    openNoteDialogue() {
      this.isShowNoteDialogue = this.isShowNoteDialogue ? false : true;
    },
    openEmailModal(item) {
      var htmlResult = $("#invoiceSendMail").html();
      this.EmailResultBody = htmlResult;
      this.sendEmailModal = true;
      this.modalItem = item;
    },
    openAddTaskModel() {
      this.showAddTaskModal = this.showAddTaskModal ? false : true;
    },
    openAddNewEvent() {
      this.showAddEventModal = this.showAddEventModal ? false : true;
    },
    openCallEvent() {
      this.showCallModal = this.showCallModal ? false : true;
    },
    openActivityModal(item) {
      if (item.activity_type == "Task") {
        this.showAddTaskModal = true;
        this.modalTaskItem = item;
      } else if (item.activity_type == "FollowUp") {
        this.showAddEventModal = true;
        this.modalFollowUpItem = item;
      } else if (item.activity_type == "Call") {
        this.showCallModal = true;
        this.modalCallItem = item;
      }
    },
    DeleteActivity(item) {
      this.modalDeleteItem = item;
      this.DeleteActivityData(this.modalDeleteItem.followup_notification_id);
    },
    openContactModal(contactDetails) {
      this.iscontactDetails = contactDetails;
      this.showContactModal = this.showContactModal ? false : true;
    },
    DeleteActivityData: function (id) {
      var vm = this;
      if (id > 0) {
        vm.confirmR(vm.$t("ConfirmDelete"), true, null, function () {
          var postJSON = {
            ids: id,
            moduleName: "CRM",
            subModuleCode: vm.$route.params.subModuleCode,
            refCode: "DELETE_VIEW_ACTIVITY",
            refId: vm.$route.params.id,
          };
          var objectPostString = JSON.stringify(postJSON);

          LeadDataService.CommonDelete(objectPostString).then(function (
            response
          ) {
            if (response.data[0].Status == "Success") {
              vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Activity')]), "success", true, vm.$t("Alert"));
              vm.loadData("activities");
            } else {
              vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Activity')]), "warning", true, vm.$t("Alert"));
            }

          });
        });
      }
    },
    openShowNotePopup: function () {
      var ths = this;
      if (
        typeof ths.checkForAdditionalPermission !== "undefined" &&
        !ths.checkForAdditionalPermission("AddNote")
      ) {
        ths.ShowAlert(
          this.$t("additionalOwnerAuthorityWarning"),
          "warning",
          true,
          ths.$t("Alert")
        );
      } else {
        ths.isShowNotePopup = true;
        $("#tab-notes").trigger("click");
        ths.loadData("notes");
      }
    },
    deleteContactFromTab(value) {
      var vm = this;
      if (value > 0) {
        vm.confirmR(vm.$t("ConfirmDelete"), true, null, function () {
          var postJSON = {
            ids: value,
            moduleName: "CRM",
            subModuleCode: vm.$route.params.subModuleCode,
            refCode: "DELETE_VIEW_CONTACTS",
            refId: vm.$route.params.id,
          };
          var objectPostString = JSON.stringify(postJSON);

          LeadDataService.CommonDelete(objectPostString).then(function (
            response
          ) {
            var box = "";
            if (response.data[0].Status == "Success") {
              $(".chkItems:checkbox:checked")
                .prop("checked", false)
                .removeAttr("checked");
              vm.loadData("contacts");
              vm.ShowAlert(vm.$t("DeletedSuccess", [vm.$t("Contact")]), 'success', true, vm.$t('Alert'));
            } else {
              vm.ShowAlert(vm.$t("DeletedError", [vm.$t("Contact")]), 'failure', true, vm.$t('Alert'));
            }
            setTimeout(function () {
              box.modal("hide");
            }, 2000);

          });
        });
      } else {
        vm.ShowAlert(vm.$t("DeletedError", [vm.$t("Contact")]), 'warning', true, vm.$t('Alert'));
      }
    },
    formatDateTime(value) {
      if (value) {
        try {
          var timeFormat = Globalize.culture().calendar.patterns.t;
          timeFormat = String(timeFormat).replace("t", "A").replace("t", "");
          var getDate = new Date(
            moment(String(value)).year(),
            moment(String(value)).month(),
            moment(String(value)).date(),
            moment(String(value)).hours(),
            moment(String(value)).minutes()
          );
          return moment(getDate, "YYYY-MM-DD HH:mm:ss").format(
            String(Globalize.culture().calendar.patterns.d).toUpperCase() +
            " " +
            String(timeFormat)
          );
        } catch (e) {
          var timeFormat = Globalize.culture().calendar.patterns.t;
          timeFormat = String(timeFormat).replace("t", "a").replace("t", "");
          return moment(String(value)).format(
            String(Globalize.culture().calendar.patterns.d).toUpperCase() +
            " " +
            String(timeFormat)
          );
        }
      }
    },
    loadData(tabName, callFrom) {
      var vm = this;
      vm.currentTab = tabName;
      vm.DisableButton();
      if (tabName == "notes") {
        vm.isNotes = true;
        vm.activeKey = 2;
        if (callFrom && callFrom == "savenote") vm.isShowNotePopup = false;
      } else if (tabName == "attachments") {
        vm.isAttachment = true;
        vm.activeKey = 3;
      } else if (tabName == "activities") {
        vm.isTask = true;
        vm.isScheduleCall = true;
        vm.isFollowup = true;
        vm.activeKey = 4;
      } else if (tabName == "emailLog") {
        vm.isSendEmail = true;
        vm.activeKey = 6;
      } else if (tabName == "calls") {
        vm.activeKey = 8;
        vm.isProduct = true;
      } else if (tabName == "GIN") {
        vm.activeKey = 7;
        vm.isProduct = true;
      }
      if (tabName != "" && tabName != null) {

        if (tabName == "attachments") {
          LeadDataService.AttachmentListing(vm.ApiURL1).then(function (
            response
          ) {

            if (response.data != null) {
              vm.attachmentData = response.data.data;
              setTimeout(function () { vm.CheckBoxBootstrap() }, 100);
              vm.noRecordForTab = false;
            } else {
              vm.noRecordForTab = true;
            }
          });
        } else if (tabName == "notes") {
          this.noteData = [];
          LeadDataService.NoteListing(vm.ApiURL1).then(function (response) {

            if (response.data != null && response.data.data.length > 0) {
              vm.noteData = response.data.data;
              vm.noRecordForTab = false;
            } else {
              vm.noRecordForTab = true;
            }
          });
        } else if (tabName == "activities") {
          LeadDataService.ActivityListing(vm.ApiURL1).then(function (response) {

            if (response.data != null && response.data.data.length > 0) {
              vm.activitiesData = response.data.data;
              vm.noRecordForTab = false;
            } else {
              vm.noRecordForTab = true;
            }
          });
        } else if (tabName == "products") {
          var productrequrl = `id=${vm.$route.params.id}&subModuleCode=${vm.$route.params.subModuleCode}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageSize=${vm.PageSize}&pageNumber=${vm.PageNumber}`;
          LeadDataService.getItemListForAssociate(productrequrl).then(function (
            response
          ) {
            if (response.data != null) {
              vm.productData = response.data.data;
              vm.productHeaders = response.data.schema;

              vm.noRecordForTab = false;
            } else {
              vm.noRecordForTab = true;
              vm.productData = null;
            }
          });
          vm.activeKey = 5;
        } else if (tabName == "calls") {
          url = `id=${vm.$route.params.id}&subModuleCode=${vm.$route.params.subModuleCode}`;
          LeadDataService.GetCallLogsListinge(url).then(function (response) {

            if (response.data != null) {
              vm.callData = response.data.data;

              vm.noRecordForTab = false;
            } else {
              vm.noRecordForTab = true;
              vm.calltData = null;
            }
          });
          vm.activeKey = 9;
        } else if (tabName == "GIN") {
          debugger
          url = `sourceId=${vm.$route.params.id}&subModuleCode=${vm.$route.params.subModuleCode}&moduleName=${vm.$route.params.moduleName}`;
          LeadDataService.GetGoodInwardForPurchaseOrder(url).then(function (
            response
          ) {
            debugger
            vm.ginData = [];
            if (response.data != null && response.data.data.length > 0) {
              var fullJSON = response.data.data;
              var groupBy = "";
              var gin_id = "";
              var gin_status = "";
              $.each(
                fullJSON,
                $.proxy(function (index, item) {
                  gin_id = item.GIN_ID;
                  groupBy = item.GIN_NUMBER;
                  gin_status = item.GIN_STATUS;
                  var chkGroup = $.grep(vm.ginData, function (element, index) {
                    return element.gin_id == gin_id;
                  });
                  if (chkGroup.length == 0) {
                    var returnedData = $.grep(
                      fullJSON,
                      function (element, index) {
                        return element.GIN_ID == gin_id;
                      }
                    );
                    if (returnedData.length > 0) {
                      var objGroup = {
                        gin_id: gin_id,
                        gin_status: gin_status,
                        gin_number: groupBy,
