    DownlaodPDF() {
      var vueObj = this;
      vueObj.isLoading = true;

      const doc = new jsPDF({
        unit: 'mm',
        format: 'a4',
      });

      const pageWidth = 210;
      const pageHeight = 297;
      const margin = 5;
      const contentWidth = pageWidth - 2 * margin;
      const contentHeight = pageHeight - 2 * margin;

      // Get the existing element with id 'pdf-content'
      const element = document.getElementById('pdf-content');

      // Create a clone of the element to avoid modifying the original
      const elementClone = element.cloneNode(true);
      elementClone.style.width = `${contentWidth}mm`;
      elementClone.style.height = 'auto';
      elementClone.style.boxSizing = 'border-box';
      elementClone.style.padding = '10mm';

      // Temporarily append to body for measurement
      document.body.appendChild(elementClone);

      const elementWidth = elementClone.offsetWidth;
      const elementHeight = elementClone.offsetHeight;

      const scaleX = contentWidth / elementWidth;
      const scaleY = contentHeight / elementHeight;
      const scaleFactor = Math.min(scaleX, scaleY);

      // Remove the clone after measurement
      document.body.removeChild(elementClone);

      // Generate PDF from the original element
      doc.html(element, {
        x: margin,
        y: margin,
        html2canvas: {
          scale: scaleFactor,
          logging: true,
          useCORS: true,
        },
        callback: function (doc) {
          vueObj.isLoading = false;
          // Use a more descriptive filename
          doc.save(`download_${vueObj.orderNumber || 'document'}.pdf`);
        },
      });
    },




